:root {
  --bg: #1a1a2e;
  --accent: #e94560;
  --text-light: #ffffff;
  --text-muted: #a0a0c0;
  --divider: #2e2e4e;
  --qr-bg: #ffffff;
  --ticket-right-bg: #16213e;
}

.ticket {
  display: flex;
  flex-direction: row;
  background-color: var(--bg);
  border-radius: 16px;
  overflow: visible;
  width: 480px;
  min-height: 200px;
  margin: 60px auto;
  position: relative;
}

.ticket-left {
  flex: 1;
  padding: 28px 24px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.event-label {
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 2px;
  color: var(--accent);
  text-transform: uppercase;
}

.event-title {
  font-size: 28px;
  font-weight: 800;
  color: var(--text-light);
  margin: 0;
  line-height: 1.1;
}

.event-subtitle {
  font-size: 13px;
  color: var(--text-muted);
  margin: 0;
  line-height: 1.4;
}

.event-meta {
  display: flex;
  flex-direction: column;
  gap: 4px;
  margin-top: 8px;
}

.meta-item {
  font-size: 12px;
  color: var(--text-muted);
  font-weight: 500;
}

.ticket-divider {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-between;
  width: 24px;
  position: relative;
}

.notch {
  width: 24px;
  height: 24px;
  background-color: #f5f5f5;
  border-radius: 50%;
  flex-shrink: 0;
  position: relative;
  z-index: 1;
}

.dashes {
  flex: 1;
  border-left: 2px dashed var(--divider);
  width: 0;
}

.ticket-right {
  width: 120px;
  background-color: var(--ticket-right-bg);
  border-radius: 0 16px 16px 0;
  padding: 20px 16px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-between;
}

.ticket-number {
  font-size: 13px;
  font-weight: 700;
  color: var(--accent);
  letter-spacing: 1px;
}

.qr-placeholder {
  width: 72px;
  height: 72px;
  background-color: var(--qr-bg);
  border-radius: 8px;
  border: 3px solid var(--accent);
}

.ticket-admit {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 2px;
  color: var(--text-muted);
  text-transform: uppercase;
}
